#include <iostream>
#include <algorithm>

int main() {
    int n, W;
    std::cin >> n >> W;
    int weight[100], value[100];
    for (int i = 0; i < n; i++) {
        std::cin >> weight[i] >> value[i];
    }
    int dp[1000][1000] = {0};
    for (int i = 1; i <= n; i++) {
        for (int w = 1; w <= W; w++) {
            if (weight[i-1] <= w) {
                dp[i][w] = std::max(dp[i-1][w], dp[i-1][w-weight[i-1]] + value[i-1]);
            } else {
                dp[i][w] = dp[i-1][w];
            }
        }
    }
    std::cout << dp[n][W] << std::endl;
    return 0;
}
